var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"지하 묘지에 침식 쐐기가 여럿 생성된 것 같다고?","JPN":"地下墓地に侵食楔が何本も生成されたみたいだって？","ENG":"You think multiple Corrupted Wedges have formed in the underground cemetery?","TWN":"地下墓地裡好像多了幾個侵蝕釘？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네. 침식체가 계속 나타나더라고요.","JPN":"はい。侵食体が次々と出てきて。","ENG":"Yeah. C.O.s keep showing up.","TWN":"是的，侵蝕體一直在出現。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아무래도 또 쐐기가 나타난 것 같아요.","JPN":"また楔が現れたんだと思います。","ENG":"Seems like another Wedge has appeared.","TWN":"看來又出現了侵蝕釘。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 더 이상 멍멍이가 할 일이 아니지 않을까?","JPN":"じゃあ、もうワンちゃんの手には負えないんじゃない？","ENG":"Then isn't this out of your hands, Puppy?","TWN":"那這就不是狗狗該做的事情了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그렇죠. 뭐, 저도 같은 생각을 하고 있긴 했는데…….","JPN":"ですよね。まあ、私も同じことを考えてますけど……","ENG":"True. I was kind of thinking the same thing, but...","TWN":"對啊。嗯，我也是這麼想的……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"비행깃값까지 생각하면 손해예요.","JPN":"飛行機代まで考えると損なんです。","ENG":"If I factor in the cost of my flight, I'm at a loss.","TWN":"但考慮到機票費用，這樣做不划算。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어떻게든 더 빨아먹어야 수지 타산이 맞을걸요?","JPN":"なんとかもっとぼったくらないと、つり合わないですよ。","ENG":"I need to squeeze more out of this to break even.","TWN":"無論如何都要再多弄點錢，才能平衡收支吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 너무 위험해.","JPN":"でも、これ以上は危険よ。","ENG":"But it's too dangerous.","TWN":"但是太危險了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"넌 퇴마사지, 침식 재난을 해결하는 사람은 아니잖아?","JPN":"あなたはエクソシストで、侵食災害を解決する人ではないでしょう？","ENG":"You're an exorcist, not a Corruption disaster specialist.","TWN":"你不是負責解決驅魔事件和侵蝕災難的人嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽…… 그건…….","JPN":"うっ……それは……","ENG":"Ugh... I know that...","TWN":"唔……可是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 이번엔 보수가 정말 많잖아요.","JPN":"でも、今回は本当に報酬がいいじゃないですか。","ENG":"But the pay this time is really good.","TWN":"但是這次報酬真的很多啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이번 기회에 더 뽑아 먹자는 거죠.","JPN":"この際もっとむしり取ってやろうってことです。","ENG":"This is my chance to milk it even more.","TWN":"趁這次機會多撈點好處吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"침식 쐐기가 생성된 지 얼마 안 된 것 같았어요.","JPN":"侵食楔はついこの前生成されたみたいでした。","ENG":"The Corrupted Wedge didn't seem like it had been here for long.","TWN":"侵蝕釘好像剛剛才出現不久。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"다른 쐐기들도 비슷한 상황 아닐까요?","JPN":"他の楔も似たような状況なんじゃないでしょうか？","ENG":"Maybe the others are in a similar state?","TWN":"其他的也差不多吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"안 돼.","JPN":"ダメ。","ENG":"No.","TWN":"不可以。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"돌아오면 에그타르트 더 구워줄 테니까, 알았지?","JPN":"戻ったらエッグタルトいっぱい焼いてあげるから、ね？","ENG":"Come back, and I'll bake you more egg tarts, all right?","TWN":"回來後我再烤蛋撻給你吃，你乖。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"또 세상 다 잃은 표정하고 있네.","JPN":"またすべてが終わったような顔をしてる。","ENG":"There it is, that look like you've lost everything.","TWN":"又是一副失去全世界的表情。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈…… 더 많은 돈…….","JPN":"金……もっとたくさんの金……","ENG":"But money... It's more money...","TWN":"錢……更多的錢……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"원래 사업을 하다 보면 손해 보는 일도 생기는 거지.","JPN":"事業をしていれば損をすることだってあるものよ。","ENG":"That's how business works. Sometimes you take a loss.","TWN":"做生意本來就會有虧損的時候。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"언제까지 이득만 보면서 살 수는 없잖아?","JPN":"いつも得ばかりとはいかないでしょう？","ENG":"You can't expect to always come out on top.","TWN":"你不能總是只想著佔便宜吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그게 잘못된 거예요.","JPN":"それが間違ってるんです。","ENG":"That's where you're wrong.","TWN":"那是不對的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"사업을 하다 보면 무조건 이익을 우선시해야 하고…….","JPN":"事業をするなら絶対的に利益を優先して……","ENG":"When you run a business, profit always comes first...","TWN":"做生意時必須優先考慮利益……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"최대한의 이득을 얻는 방법을 생각해야죠.","JPN":"最大限に得する方法を考えないと。","ENG":"So you have to figure out how to maximize your gains.","TWN":"我們要想辦法獲得最大的利益。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니도 가만 보면 사업 센스가 없다니까.","JPN":"姉さんたら事業へのセンスがないんだから。","ENG":"Honestly, you have zero business sense.","TWN":"仔細想想，其實姊姊沒有商業頭腦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"사업 센스 같은 거 없어도 돼.","JPN":"事業センスなんてなくてもいいわ。","ENG":"I don't need business sense.","TWN":"不需要什麼商業頭腦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};